interface Props {
  src: string;
  alt?: string;
  size?: number;
  class?: string;
}

const {
  src,
  alt = "LINE公式アカウント QRコード",
  size = 180,
  class: className,
} = Astro.props;
---

<div class:list={["bg-white p-4 rounded-xl shadow-sm border border-neutral-100 inline-block", className]}>
  <img
    src={src}
    alt={alt}
    width={size}
    height={size}
    class="block"
    loading="lazy"
  />
  <p class="text-xs text-neutral-500 text-center mt-2">
    QRコードを読み取って追加
  </p>
</div>

