import Container from "../ui/Container.astro";
import Button from "../ui/Button.astro";
import QRCode from "../ui/QRCode.astro";
import FadeInSection from "../ui/FadeInSection";
import { LINE_CONFIG } from "../../lib/constants";

interface Props {
  heading?: string;
  description?: string;
  qrCodeSrc?: string;
  lineUrl?: string;
  class?: string;
}

const {
  heading = "お気軽にご相談ください",
  description = "介護に関するお悩みや、サービスについてのご質問など、LINEでお気軽にお問い合わせください。",
  qrCodeSrc = LINE_CONFIG.qrCodePath,
  lineUrl = LINE_CONFIG.url,
  class: className,
} = Astro.props;
---

<section class:list={["py-16 md:py-24 bg-gradient-to-br from-sakura-50 to-white", className]}>
  <Container>
    <FadeInSection client:idle>
      <div class="max-w-4xl mx-auto text-center">
        <h2 class="text-2xl md:text-3xl lg:text-4xl font-bold text-neutral-900 mb-4">
          {heading}
        </h2>
        <p class="text-neutral-600 mb-10 max-w-2xl mx-auto">
          {description}
        </p>

        <div class="flex flex-col md:flex-row items-center justify-center gap-8 md:gap-12">
          {/* QR Code */}
          <div class="flex-shrink-0">
            <QRCode src={qrCodeSrc} />
          </div>

          {/* CTA Content */}
          <div class="text-center md:text-left">
            <p class="text-neutral-600 mb-4">
              スマートフォンでQRコードを読み取るか、<br class="hidden md:block" />
              下のボタンからLINE公式アカウントを追加してください。
            </p>

            <Button
              href={lineUrl}
              variant="primary"
              size="lg"
              class="bg-[#06C755] hover:bg-[#05b34d] border-none"
              target="_blank"
              rel="noopener noreferrer"
            >
              <svg class="w-5 h-5 mr-2" viewBox="0 0 24 24" fill="currentColor">
                <path d="M19.365 9.863c.349 0 .63.285.63.631 0 .345-.281.63-.63.63H17.61v1.125h1.755c.349 0 .63.283.63.63 0 .344-.281.629-.63.629h-2.386c-.345 0-.627-.285-.627-.629V8.108c0-.345.282-.63.63-.63h2.386c.349 0 .63.285.63.63 0 .349-.281.63-.63.63H17.61v1.125h1.755zm-3.855 3.016c0 .27-.174.51-.432.596-.064.021-.133.031-.199.031-.211 0-.391-.09-.51-.25l-2.443-3.317v2.94c0 .344-.279.629-.631.629-.346 0-.626-.285-.626-.629V8.108c0-.27.173-.51.43-.595.06-.023.136-.033.194-.033.195 0 .375.104.495.254l2.462 3.33V8.108c0-.345.282-.63.63-.63.345 0 .63.285.63.63v4.771zm-5.741 0c0 .344-.282.629-.631.629-.345 0-.627-.285-.627-.629V8.108c0-.345.282-.63.63-.63.346 0 .628.285.628.63v4.771zm-2.466.629H4.917c-.345 0-.63-.285-.63-.629V8.108c0-.345.285-.63.63-.63.348 0 .63.285.63.63v4.141h1.756c.348 0 .629.283.629.63 0 .344-.282.629-.629.629M24 10.314C24 4.943 18.615.572 12 .572S0 4.943 0 10.314c0 4.811 4.27 8.842 10.035 9.608.391.082.923.258 1.058.59.12.301.079.766.038 1.08l-.164 1.02c-.045.301-.24 1.186 1.049.645 1.291-.539 6.916-4.078 9.436-6.975C23.176 14.393 24 12.458 24 10.314"/>
              </svg>
              LINEで問い合わせる
            </Button>

            <p class="mt-4 text-sm text-neutral-500">
              対応時間：平日 9:00〜18:00
            </p>
          </div>
        </div>
      </div>
    </FadeInSection>
  </Container>
</section>

